import React, { useState, useEffect, useRef } from 'react';
import { clsx } from "clsx";

const NOTICES = [
  { id: 1, type: "info", text: "Welcome to the National Digital Internship Management System!" },
  { id: 2, type: "success", text: "New Update: Live application tracking is now active for all users." },
  { id: 3, type: "warning", text: "Reminder: Weekly logbooks must be submitted by Friday 5PM." },
  { id: 4, type: "info", text: "Companies: Please review pending student applications promptly." }
];

export default function SystemNotice() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef(null);

  // Auto-play interval for the marquee
  useEffect(() => {
    if (isOpen) return; // Pause auto-play when dropdown is open
    const timer = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % NOTICES.length);
    }, 4000); // Rotate every 4 seconds
    return () => clearInterval(timer);
  }, [isOpen]);

  // Handle click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const currentNotice = NOTICES[currentIndex];

  const getIcon = (type) => {
    switch (type) {
      case "success": return "🎉";
      case "warning": return "⚠️";
      case "danger": return "🚨";
      default: return "📢";
    }
  };

  return (
    <header className="bg-white border-b border-gray-200 h-16 flex items-center justify-end px-6 sticky top-0 z-40 shrink-0 shadow-sm">
      <div className="relative" ref={dropdownRef}>

        {/* Auto-playing Notice Banner Button */}
        <button 
          onClick={() => setIsOpen(!isOpen)}
          className="flex items-center gap-3 bg-indigo-50 hover:bg-indigo-100 border border-indigo-100 text-indigo-700 px-4 py-2 rounded-full transition-all duration-300 max-w-md group"
        >
          <span className="animate-pulse">{getIcon(currentNotice.type)}</span>
          <div className="overflow-hidden w-64 text-left relative h-5">
            <div 
              key={currentNotice.id} 
              className="absolute w-full truncate text-sm font-medium animate-slide-up"
            >
              {currentNotice.text}
            </div>
          </div>
          <span className={clsx("text-xs transition-transform duration-300", isOpen ? "rotate-180" : "rotate-0")}>▼</span>
        </button>

        {/* Dropdown Menu */}
        {isOpen && (
          <div className="absolute top-full right-0 mt-2 w-96 bg-white border border-gray-100 rounded-xl shadow-xl overflow-hidden animate-fade-in origin-top-right">
            <div className="bg-gray-50 px-4 py-3 border-b border-gray-100 flex justify-between items-center">
              <h3 className="font-semibold text-gray-800 text-sm">System Notices</h3>
              <span className="bg-indigo-100 text-indigo-700 text-xs px-2 py-0.5 rounded-full font-medium">Auto-playing</span>
            </div>
            <div className="max-h-80 overflow-y-auto">
              {NOTICES.map((n, i) => (
                <div 
                  key={n.id}
                  onClick={() => { setCurrentIndex(i); setIsOpen(false); }}
                  className={clsx(
                    "px-4 py-3 border-b border-gray-50 cursor-pointer hover:bg-gray-50 flex gap-3 transition-colors",
                    i === currentIndex && "bg-indigo-50/50"
                  )}
                >
                  <span className="text-base mt-0.5">{getIcon(n.type)}</span>
                  <p className={clsx("text-sm", i === currentIndex ? "text-indigo-900 font-medium" : "text-gray-600")}>
                    {n.text}
                  </p>
                </div>
              ))}
            </div>
            <div className="px-4 py-2 bg-gray-50 text-center border-t border-gray-100">
              <p className="text-xs text-gray-400">Notices automatically rotate every 4s</p>
            </div>
          </div>
        )}
      </div>
    </header>
  );
}
